const d = $input.first().json;
const channel = d.channel || {};
const basePersonality = d.basePersonality || {};
const personality = channel.useSharedPersonality ? basePersonality : (channel.personality || basePersonality);

const level = (n) => (n < 34 ? 'baixa' : n < 67 ? 'equilibrada' : 'alta');

let systemPrompt = (d.baseInstructions || '').trim();
if (channel.instructions?.trim()) {
  systemPrompt += '\n\nInstrucoes do canal:\n' + channel.instructions.trim();
}
systemPrompt += '\n\nDiretrizes de estilo:';
systemPrompt += '\n- Formalidade: ' + level(personality.formality ?? 50);
systemPrompt += '\n- Objetividade: ' + level(personality.objectivity ?? 50);
systemPrompt += '\n- Nivel tecnico: ' + level(personality.technicalLevel ?? 50);
systemPrompt += '\n- Estilo de escrita: ' + (personality.writingStyle || 'equilibrado');
systemPrompt += '\n- Emojis: ' + (personality.emojiUsage || 'as_vezes');
systemPrompt += '\n- Tamanho das respostas: ' + (personality.responseLength || 'media');

const kc = (d.knowledgeContext || '').trim();
if (kc) {
  systemPrompt += '\n\n## Base de conhecimento relevante\n' + kc;
  systemPrompt += '\n\nUse apenas as informacoes acima quando pertinentes. Se nao souber, diga que nao tem a informacao.';
}

const temperature = (personality.temperature ?? 50) / 100;
const max_tokens = { curta: 256, media: 512, longa: 1024 }[personality.responseLength] || 512;
const top_p = 0.5 + ((personality.creativity ?? 50) / 200);

return [{ json: { systemPrompt, personality, llmParams: { temperature, max_tokens, top_p } } }];
